# The middle way between strict typing and dynamic enlightenment

def process_karma(soul):
    while soul.samsara:
        try:
            enlightenment = soul.meditate(cycles=1e6)
            if enlightenment.detach():
                soul.nirvana = True
        except AttachmentError as e:
            soul.reincarnate(debug=True)
        finally:
            del desire
    return soul.achieve()

